        val followEntities = listOf(
            FollowEntity(id = "f1", followerId = follower1Id, followingId = userId),
            FollowEntity(id = "f2", followerId = follower2Id, followingId = userId),
        )
        val followerUsers = listOf(
            UserEntity(id = follower1Id, nickname = "user2"),
            UserEntity(id = follower2Id, nickname = "user3"),
