`user/src/main/kotlin/com/maum/backend/service/user/UserService.kt`

```kotlin
package com.maum.backend.service.user

import com.maum.backend.entity.follow.FollowEntity
import com.maum.backend.entity.user.UserEntity
import com.maum.backend.repository.follow.FollowRepository
import com.maum.backend.repository.user.UserRepository
import org.springframework.stereotype.Service
import org.springframework.transaction.annotation.Transactional

class AlreadyFollowingException(message: String) : RuntimeException(message)
class SelfFollowException(message: String) : RuntimeException(message)
class UserNotFoundException(message: String) : RuntimeException(message)
class NotFollowingException(message: String) : RuntimeException(message)

data class FollowResult(val followId: String, val followerId: String, val followingId: String)
data class UserSummary(val id: String, val nickname: String)

@Service
class UserService(
    private val userRepository: UserRepository,
    private val followRepository: FollowRepository,
) {
    /**
     * 팔로우 실행
     * - 자기 자신 팔로우 불가
     * - 이미 팔로우 중이면 AlreadyFollowingException
     * - 대상 유저가 없으면 UserNotFoundException
     */
    @Transactional
    fun follow(followerId: String, followingId: String): FollowResult {
        if (followerId == followingId) {
            throw SelfFollowException("자기 자신을 팔로우할 수 없습니다.")
        }

        userRepository.findById(followingId).orElseThrow {
            UserNotFoundException("팔로우 대상 유저를 찾을 수 없습니다: $followingId")
        }

        if (followRepository.existsByFollowerIdAndFollowingId(followerId, followingId)) {
            throw AlreadyFollowingException("이미 팔로우 중입니다.")
        }

        val followEntity = FollowEntity(
            followerId = followerId,
            followingId = followingId,
        )
        val saved = followRepository.save(followEntity)
        return FollowResult(followId = saved.id, followerId = saved.followerId, followingId = saved.followingId)
    }

    /**
     * 언팔로우 실행
     * - 팔로우 중이 아니면 NotFollowingException
     */
    @Transactional
    fun unfollow(followerId: String, followingId: String) {
        if (!followRepository.existsByFollowerIdAndFollowingId(followerId, followingId)) {
            throw NotFollowingException("팔로우 중이 아닙니다.")
        }
        followRepository.deleteByFollowerIdAndFollowingId(followerId, followingId)
    }

    /**
     * 팔로워 목록 조회 (나를 팔로우하는 사람들)
     */
    @Transactional(readOnly = true)
    fun getFollowers(userId: String): List<UserSummary> {
        userRepository.findById(userId).orElseThrow {
            UserNotFoundException("유저를 찾을 수 없습니다: $userId")
        }
        val followerIds = followRepository.findAllByFollowingId(userId).map { it.followerId }
        if (followerIds.isEmpty()) return emptyList()
        return userRepository.findByIdIn(followerIds).map { UserSummary(it.id, it.nickname) }
    }

    /**
     * 팔로잉 목록 조회 (내가 팔로우하는 사람들)
     */
    @Transactional(readOnly = true)
    fun getFollowings(userId: String): List<UserSummary> {
        userRepository.findById(userId).orElseThrow {
            UserNotFoundException("유저를 찾을 수 없습니다: $userId")
        }
        val followingIds = followRepository.findAllByFollowerId(userId).map { it.followingId }
        if (followingIds.isEmpty()) return emptyList()
        return userRepository.findByIdIn(followingIds).map { UserSummary(it.id, it.nickname) }
    }

    /**
     * 팔로워 수 조회
     */
    @Transactional(readOnly = true)
    fun getFollowerCount(userId: String): Long {
        return followRepository.countByFollowingId(userId)
    }

    /**
     * 팔로잉 수 조회
     */
    @Transactional(readOnly = true)
    fun getFollowingCount(userId: String): Long {
        return followRepository.countByFollowerId(userId)
    }

    /**
     * 팔로우 여부 확인
     */
    @Transactional(readOnly = true)
    fun isFollowing(followerId: String, followingId: String): Boolean {
        return followRepository.existsByFollowerIdAndFollowingId(followerId, followingId)
    }
}
```

